1944	const normalizeMarkdownImageDestination = (destination: string): string | null => {
1945	  const trimmed = destination.trim();
1946	  if (!trimmed || trimmed.startsWith("#") || trimmed.startsWith("//") || urlSchemePattern.test(trimmed)) return null;
1947	
1948	  const unwrapped = trimmed.startsWith("<") && trimmed.endsWith(">") ? trimmed.slice(1, -1).trim() : trimmed;
1949	  if (!unwrapped || unwrapped.startsWith("#") || unwrapped.startsWith("//") || urlSchemePattern.test(unwrapped)) return null;
1950	
1951	  try {
